var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"다들 정신 차려라! 전하께서 보고 계신다!","JPN":"みんなしっかりしろ！　殿下がご観戦なさっている！","ENG":"Keep it together! His Highness is watching even now!","TWN":"大家振作點！殿下正看著呢！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"그대들은 이미 죽은 자들이다! 어찌 죽음이 또 두렵단 말이냐!","JPN":"そなたらはすでに死んだ身だ！　どうして死を恐れることがあろうか！","ENG":"You’re already dead! How can death frighten you again?","TWN":"你們是已死的人！還會怕死嗎！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"깃발은 꺾이지 않았다! 나와 함께 달려 나가자!","JPN":"旗は折れていない！　私と共に駆け抜けよう！","ENG":"Our banner still stands! Charge with me!","TWN":"旗幟仍舊在飄揚！跟我一起衝吧！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"큿?!","JPN":"くっ！？","ENG":"Erck?!","TWN":"咳？！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L7_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"여어, 등대털이범 아가씨. 오랜만이야.","JPN":"よお、灯台荒らしのお嬢さん。久しぶりだな。","ENG":"Yo, lighthouse raider-lady. Long time no see.","TWN":"喂，燈塔小偷小姐，好久不見啦～"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"지난번에는 신세를 많이 졌었지.","JPN":"この前は大変お世話になったぞ。","ENG":"I owe you for last time.","TWN":"上次受到你不少的照顧呢！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"뭐, 꼭 나쁘지만은 않았어. 덕분에 이런 장비도 얻었으니까.","JPN":"ま、悪いことばかりじゃなかったぜ。おかげでこんな装備も手に入れたし。","ENG":"Well, I guess it wasn’t that bad. I got my hands on this gear thanks to you.","TWN":"也不全都是壞事啦，至少我還有獲得這身裝備的嘛！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"하지만 그렇다고 계속 빚지고만 살 수는 없지.","JPN":"けど、ずっと世話になるわけにはいかないよな。","ENG":"However, I don’t like to have outstanding debts.","TWN":"不過也不能因為這樣，就一直欠你人情。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_ELECTRIC_08"},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"오늘은 기대하라고, 짜릿하게 해 줄 테니까.","JPN":"今日は楽しみにしてろよ、ビリビリさせてやるからな。","ENG":"I hope you’re prepared, because I’m gonna electrify you.","TWN":"敬請期待，今天就給你個痛快！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"그때 만났던 번개의 전사인가……","JPN":"あの時の稲妻の戦士か……","ENG":"You must be the lightning warrior from last time...","TWN":"是那時候遇到的閃電戰士嗎……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"예전의 나라면…… 그대와의 싸움에서 어떤 의미도 느끼지 못했겠지.","JPN":"昔の私なら……そなたとの闘いで何の意味も感じられなかっただろう。","ENG":"Previously, I wouldn’t have felt anything from fighting against you.","TWN":"若是以前的我……和你交手對我而言完全沒有任何意義。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"하지만 지금은 내게도 승리를 해야 할 이유가 있어!","JPN":"だが今は私にも勝つべき理由があるんだ！","ENG":"However, I also have a reason to win now!","TWN":"但現在的我，有非贏不可的理由！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"그거 좋군. 충고하는데 전력으로 덤비라고.","JPN":"それはいいな。言っておくけど、全力で来いよ。","ENG":"Sounds good. Just some advice, you’d better come at me with everything you’ve got.","TWN":"非常好！我可是事先警告你，千萬不要有所保留。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"이쪽은 신도 쓰러트린 적이 있으니까!","JPN":"こちとら神にも勝ったことがあるんだからな！","ENG":"After all, I’ve even defeated a god before!","TWN":"畢竟我可是打倒過神的呢！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_STORM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아군이 유리한 장소를 만들어내고 적에게 결전을 강요한다라……","JPN":"味方に有利な場所を作り上げ、敵に決戦を迫る……","ENG":"Creating an advantageous position for our troops and forcing the enemy into battle...","TWN":"製造出對我方有利的地點後，強迫敵人開戰……"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"불리했던 전황을 이렇게 단숨에 뒤집어 버리다니, 역시 대단하시군요.","JPN":"不利だった戦況をこんなに一気に覆すなんて、やはりお見事ですね。","ENG":"Flipping the tables on the enemy in a single move... You truly are impressive.","TWN":"竟然瞬間就將原本不利的局勢扭轉過來，確實厲害！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"말 그대로 <color=#ffd34c>교전</color>이 아닌 <color=#ffd34c>전쟁</color>에 특화된 능력이라고 할까요?","JPN":"言葉どおり、<color=#ffd34c>交戦</color>ではなく<color=#ffd34c>戦争</color>に特化した能力と言いますか。","ENG":"I may say that it’s an ability specialized for <color=#ffd34c>war</color>, not <color=#ffd34c>combat</color>.","TWN":"果然是名不虛傳，不是為<color=#ffd34c>交戰</color>而生，而是為<color=#ffd34c>戰爭</color>而生的嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"칭찬은 고맙군. 하지만 단순한 임기응변일 뿐이지.","JPN":"誉めてくれて感謝する。だが単なる臨機応変に過ぎない。","ENG":"I appreciate the compliment. However, this is merely adapting to the circumstances.","TWN":"謝謝你的稱讚，不過這只是單純的危機處理而已。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"결국 승부를 결정짓는 건 정면 대결이니까.","JPN":"結局勝負を決めるのは正面対決なのだからな。","ENG":"After all, it’s the head-on battles that determine the outcome of the war.","TWN":"最終勝負還是取決於正面對決。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"아무튼 시간을 조금 벌었으니 이제 본대를 상대할 방법을 생각해야……","JPN":"とにかく少しは時間を稼いだから、これからは本隊を相手する方法を考えないと……","ENG":"Anyway, now that I’ve bought us some time, we need to think of how to face their main force...","TWN":"總之多少有爭取到一些時間，現在該想想如何對付……"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"저기, 부사장님?","JPN":"あの、副社長？","ENG":"Umm, Vice President?","TWN":"喂，副總？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"서윤 소대장? 무슨 일이죠?","JPN":"アオイ小隊長？　どうしましたか？","ENG":"Commander Seo Yoon? What happened?","TWN":"徐芸小隊長？有什麼事嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"바쁘신데 죄송하지만 손님이 와서 말이죠.","JPN":"忙しいところすみませんが、お客さんが来ましたので。","ENG":"Sorry to disturb you, but we have guests.","TWN":"不好意思，這麼忙還打擾你，不過有客人造訪。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"손님? 대체 이곳에 무슨 손님이 온다는 거죠?","JPN":"お客さん？　一体ここに何のお客さんですか？","ENG":"Guests? How did guests arrive in a place like this?","TWN":"客人？這種地方會有什麼客人？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"문! 문 열어 줘요! 들여보내 달라고요!","JPN":"扉！　扉開けて！　入らせてくださいよ！","ENG":"The door! Please open the door! Let us in!","TWN":"開門！快開門！快讓我進去！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"그, 그래요. 생각해 보니까 역시 저희도 파티를 풀기 싫은 것 같아요. 아니, 그래도 싸우기는 싫지만……","JPN":"そ、そうです。考えてみたらやっぱり私たちもパーティーを解散したくなかったんです。いや、でも戦うのはいやですけど……","ENG":"P-please let us in. Thinking back it, we don’t want to leave the party. I mean, I still don’t want to fight, but...","TWN":"對…對啊，仔細想想，我們也不想隊伍解散，可是又不想打打殺殺的……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"체험 캠프 멤버들?","JPN":"体験キャンプのメンバー？","ENG":"The experience camp participants?","TWN":"體驗營的成員？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"어떻게 된 일이지? 분명 오비탈 베이스를 폭파시킨 후 이탈하지 않았나?","JPN":"どういうことだ？　確かオービタルベースを爆発した後に離脱したのではなかったか？","ENG":"What’s going on? Didn’t you guys escape after detonating the Orbital Base?","TWN":"這是怎麼回事？你們不是在軌道基地爆炸後就離開了嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"그게…… 그러니까……","JPN":"それが……えっと……","ENG":"Well... You see...","TWN":"那個……就那個……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"물론 그 말대로 탈출선을 타고 후방으로 이탈하려고 했지.","JPN":"今言ったとおり、確かに脱出船に乗って後方へと離脱しようとしたんだ。","ENG":"Of course we tried to take the escape pod from the back.","TWN":"原本是想搭逃生船離開的啦，"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"하지만 조금 곤란한 일이 벌어져서 말이야.","JPN":"だが、それがちょっと困ったことになってな。","ENG":"But, we ran into some trouble.","TWN":"只是發生一些麻煩事。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"곤란한 일이라니?","JPN":"困ったこと？","ENG":"Some trouble?","TWN":"什麼麻煩事？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"후방에서 이쪽으로 오는 친구들을 만났거든.","JPN":"後方でこちらに向かってくる奴に会ったんだ。","ENG":"We met a couple of friends on our way back to here.","TWN":"就剛好遇到要來這裡的朋友。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"참고로 별로 반갑지는 않을 거야.","JPN":"ちなみに、あまり嬉しい奴じゃねえぞ。","ENG":"The kind of friends that aren’t welcome.","TWN":"不過提醒一下，是不太受歡迎的朋友。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이런, 벌써 도착했나 본데?","JPN":"おっと、もう着いたみてえだな。","ENG":"Ah crap, they’re arriving already.","TWN":"可惡，這麼快就到啦？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};